void acquire(struct spinlock *lk) {
	push_off();
	while(__sync_lock_test_and_set(&lk->locked, 1) != 0)
		;
	__sync_synchronize();
	lk->cpu = mycpu();
}
void release(struct spinlock *lk) {
	lk->cpu = 0;
	__sync_synchronize();
	__sync_lock_release(&lk->locked);
	pop_off();
}

void push_off(void) {
	int old = intr_get();
	intr_off();
	struct cpu *c = mycpu();
	if (c->noff == 0) c->intena = old;
	c->noff += 1;
}
void pop_off(void) {
	struct cpu *c = mycpu();
	c->noff -= 1;
	if(c->noff == 0 && c->intena) intr_on();
}

